import{_ as o,o as t,c as n,a2 as a}from"./chunks/framework.CHeM0PsO.js";const g=JSON.parse('{"title":"RFC 0009 — Internal package codenames","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0009-internal-package-codenames.md","filePath":"rfcs/0009-internal-package-codenames.md"}'),d={name:"rfcs/0009-internal-package-codenames.md"};function s(r,e,i,c,l,h){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="rfc-0009-—-internal-package-codenames" tabindex="-1">RFC 0009 — Internal package codenames <a class="header-anchor" href="#rfc-0009-—-internal-package-codenames" aria-label="Permalink to &quot;RFC 0009 — Internal package codenames&quot;">​</a></h1><p><strong>Status:</strong> Withdrawn (deferred)<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> <code>packages/ui</code> → <code>mosaic</code>, <code>packages/mailer</code> → <code>dispatch</code>, <code>packages/db</code> → <code>database</code>; all importers; both <code>next.config.ts</code>; <code>eslint.config.ts</code>; <code>runtime/src</code>; docs (CLAUDE.md, design-system, plugin-development, architecture)<br><strong>Incorporated into plan:</strong> No — <strong>withdrawn/deferred</strong> at this time (decision-log row in SRS §6). The names (<code>ui</code>→<code>mosaic</code>, <code>mailer</code>→<code>dispatch</code>, <code>db</code>→<code>database</code>) are not adopted; the pre-publish rename window stays open (nothing is on npm yet), so this can be revisited before first npm publish without breakage.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Give three workspace packages <strong>memorable codenames</strong> under the existing <code>@sovereignfs/*</code> scope, while it is still free to do so — <strong>before</strong> anything is published to npm:</p><table tabindex="0"><thead><tr><th>Today</th><th>Becomes</th><th>Role</th></tr></thead><tbody><tr><td><code>@sovereignfs/ui</code></td><td><strong><code>@sovereignfs/mosaic</code></strong></td><td>Design system (components + <code>--sv-</code> tokens)</td></tr><tr><td><code>@sovereignfs/mailer</code></td><td><strong><code>@sovereignfs/dispatch</code></strong></td><td>Outbound delivery (email now; SMS/push later)</td></tr><tr><td><code>@sovereignfs/db</code></td><td><strong><code>@sovereignfs/database</code></strong></td><td>Drizzle client + platform schema + bootstrap</td></tr></tbody></table><p><code>@sovereignfs/sdk</code>, <code>@sovereignfs/manifest</code>, and <code>@sovereignfs/tsconfig</code> keep their functional names — <code>sdk</code> is the universally-understood plugin-contract term, and <code>manifest</code>/<code>tsconfig</code> are conventional and self-describing.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Sovereign&#39;s packages are its building blocks; memorable names give the platform identity and make the architecture more legible as a product (not just a dependency graph). The <strong>timing is the point</strong>: there is no CI/publish pipeline yet (that is the pending Task 0.5.8) and <strong>no public release</strong>, so no package has reached npm and there are no third-party plugins. Renaming now is <strong>pure internal churn with zero external breakage</strong>. Once <code>ui</code> ships to npm it becomes a public design-system contract and a rename would be a breaking change under NFR-04 — so this window closes soon.</p><p><code>mailer → dispatch</code> additionally <strong>reframes</strong> the package (see below); <code>ui → mosaic</code> evokes composing a surface from tiles/components; <code>db → database</code> is a cosmetic preference for the full word.</p><h2 id="mailer-→-dispatch-a-deliberate-scope-reframe" tabindex="-1"><code>mailer</code> → <code>dispatch</code>: a deliberate scope reframe <a class="header-anchor" href="#mailer-→-dispatch-a-deliberate-scope-reframe" aria-label="Permalink to &quot;`mailer` → `dispatch`: a deliberate scope reframe&quot;">​</a></h2><p><code>dispatch</code> is renamed <em>and</em> re-conceived as the platform&#39;s <strong>unified outbound- delivery engine</strong>, not an SMTP-only helper. Email is the only channel today; <strong>SMS, web/native push (APNs/FCM), and webhooks</strong> are intended future channels.</p><p>This is coherent with the rest of the plan rather than speculative:</p><ul><li>It layers cleanly beneath the reserved <code>sdk.notifications</code> / <code>sdk.events</code> SDK surfaces and the PWA + native-mobile push direction already documented.</li><li>Every channel stays <strong>optional and no-op when unconfigured</strong>, exactly as SMTP is today — preserving NFR-02 (no external dependency for core).</li><li>Plugin-facing surfaces (<code>sdk.mailer</code>, and a future <code>sdk.notifications</code>) route <strong>through</strong> <code>dispatch</code>; the codename names the role better than &quot;mailer&quot; would.</li></ul><p><strong>Simplicity caveat (honored):</strong> the name is aspirational, but multi-channel support is <strong>not built until there is concrete need</strong> (&quot;simplicity over premature flexibility&quot;). The package&#39;s <code>description</code> + README state the intended scope so the codename is never a mystery to a contributor reading email-only code today.</p><h2 id="reconciling-with-existing-conventions" tabindex="-1">Reconciling with existing conventions <a class="header-anchor" href="#reconciling-with-existing-conventions" aria-label="Permalink to &quot;Reconciling with existing conventions&quot;">​</a></h2><ul><li><strong>The <code>@sovereignfs/*</code> scope is retained.</strong> Only the final path segment changes. The single-owned-scope rationale (avoiding dependency-confusion with scopes owned by others) is unaffected; the &quot;published vs internal&quot; signal remains <code>&quot;private&quot;: true</code>, not the scope.</li><li><strong>CLAUDE.md &quot;Package naming and scope&quot;</strong> is updated to reflect the codenames and to carry a <strong>codename ↔ function mapping table</strong>, so the names are discoverable.</li><li><strong>&quot;Clarity beats clever&quot; is the real tension.</strong> The project deliberately favors descriptive names (e.g. the <code>--sv-color-text-primary</code> token rule). We accept the codenames for these three only, and mitigate the clarity cost with: an accurate <code>package.json description</code>, a one-line README per package, and the CLAUDE.md mapping table. <code>sdk</code>/<code>manifest</code>/<code>tsconfig</code> stay functional precisely to keep the contract surface unambiguous.</li><li><strong><code>mosaic</code> is the future public contract.</strong> Because <code>ui</code> is the design system consumed by third-party plugins, the chosen codename becomes the published name going forward; <code>docs/design-system.md</code> and <code>docs/plugin-development.md</code> import examples update from <code>@sovereignfs/ui</code> to <code>@sovereignfs/mosaic</code>.</li></ul><h2 id="impact-when-the-rename-is-performed-deferred-to-a-later-task" tabindex="-1">Impact when the rename is performed (deferred to a later task) <a class="header-anchor" href="#impact-when-the-rename-is-performed-deferred-to-a-later-task" aria-label="Permalink to &quot;Impact when the rename is performed (deferred to a later task)&quot;">​</a></h2><p>A single mechanical, repo-wide change. For each of the three packages:</p><ul><li>its <code>package.json</code> <code>name</code> (and <code>description</code>);</li><li>every dependent <code>package.json</code> dependency entry;</li><li>all <code>import</code> / <code>from</code> statements;</li><li>the <code>transpilePackages</code> arrays in <code>runtime/next.config.ts</code> and <code>apps/auth/next.config.ts</code>;</li><li>the <strong>ESLint SDK-boundary rule</strong> restricted list — <code>db</code> and <code>mailer</code> are named there (<code>eslint.config.ts</code>); after rename it must reference <code>database</code> / <code>dispatch</code>;</li><li><code>runtime/src/docs-parity.test.ts</code> (imports <code>@sovereignfs/db</code>) and <code>runtime/src/db.ts</code> (re-exports);</li><li>docs: the CLAUDE.md naming section, <code>docs/design-system.md</code>, <code>docs/plugin-development.md</code>, <code>docs/architecture.md</code>, and any <code>docs/upgrade.md</code> note.</li></ul><p>Representative high-touch areas: <strong><code>db</code> → <code>database</code></strong> (~15 runtime files + the SDK), <strong><code>ui</code> → <code>mosaic</code></strong> (~12 references incl. both Next configs and the design docs), <strong><code>mailer</code> → <code>dispatch</code></strong> (~1 source file + the boundary rule + the SDK mailer surface). <code>turbo.json</code> references <code>@sovereignfs/manifest</code> (not renamed) and the pnpm <code>catalog:</code> entries are unaffected (<code>tsconfig</code> not renamed).</p><p>The rename should be <strong>one PR, done in one pass</strong> (a rename split across PRs leaves the build broken in between), and <strong>must precede first npm publish</strong>.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>Codenames in docs only</strong> (keep functional npm names). Zero churn, but the maintainer wants real package identity, and the pre-publish window makes the actual rename cheap and breakage-free.</li><li><strong>Rename all six</strong> (incl. <code>sdk</code>/<code>manifest</code>/<code>tsconfig</code>). Unnecessary and counterproductive — <code>sdk</code> is the clearest term for the plugin contract; <code>manifest</code>/<code>tsconfig</code> are conventional.</li><li><strong>Defer until post-v1.</strong> Would turn the <code>ui</code> rename into a breaking npm change and a migration burden for plugin authors. Rejected — do it now.</li><li><strong><code>postman</code> for the mailer.</strong> Conceptually fine under our scope (no npm collision), but <code>dispatch</code> better fits the broadened multi-channel role and avoids evoking the unrelated API client.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>Timing vs Task 0.5.8.</strong> Guarantee the rename lands before the publish pipeline / first release.</li><li><strong><code>dispatch</code> scope in the SRS.</strong> Whether to add a short note tying <code>dispatch</code> to the reserved <code>sdk.notifications</code> surface so the broadened role is recorded beyond this RFC.</li><li><strong><code>sdk.mailer</code> evolution.</strong> As channels are added, whether the plugin-facing surface stays <code>sdk.mailer</code> or is supplemented by <code>sdk.notifications</code> — out of scope here; flagged for a future RFC.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft; renames ui→mosaic, mailer→dispatch (multi-channel), db→database.</td></tr><tr><td>—</td><td>Jun 2026</td><td>Withdrawn / deferred; not incorporated. The pre-publish rename window stays open — revisit before first npm publish.</td></tr></tbody></table>',28)])])}const m=o(d,[["render",s]]);export{g as __pageData,m as default};
